#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N,M; long long K; scanf("%d %d %lld", &N, &M, &K);
        int rows=N, cols=M;
        // allocate (N+1)*(M+1) prefix sum, 1‑based
        long long *pref = (long long*)calloc((rows+1)*(cols+1), sizeof(long long));
        for(int i=1;i<=rows;i++){
            for(int j=1;j<=cols;j++){
                long long a; scanf("%lld", &a);
                long long b = a - K;
                pref[i*(cols+1)+j] = b + pref[(i-1)*(cols+1)+j] + pref[i*(cols+1)+j-1] - pref[(i-1)*(cols+1)+j-1];
            }
        }
        long long ans=0;
        for(int i=1;i<=rows;i++){
            for(int j=1;j<=cols;j++){
                int maxSize = rows - i + 1;
                if(cols - j + 1 < maxSize) maxSize = cols - j + 1;
                int lo=1, hi=maxSize, best=-1;
                while(lo<=hi){
                    int mid = (lo+hi)/2;
                    int i2 = i+mid-1, j2 = j+mid-1;
                    long long sum = pref[i2*(cols+1)+j2] - pref[(i-1)*(cols+1)+j2] - pref[i2*(cols+1)+j-1] + pref[(i-1)*(cols+1)+j-1];
                    if(sum>=0){ best=mid; hi=mid-1; }
                    else lo=mid+1;
                }
                if(best!=-1) ans += (long long)(maxSize - best + 1);
            }
        }
        printf("%lld\n", ans);
        free(pref);
    }
    return 0;
}

