import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int M = fs.nextInt();
            long K = fs.nextLong();
            long[][] pref = new long[N + 1][M + 1];
            for (int i = 1; i <= N; i++) {
                for (int j = 1; j <= M; j++) {
                    long a = fs.nextLong();
                    long b = a - K;
                    pref[i][j] = b + pref[i - 1][j] + pref[i][j - 1] - pref[i - 1][j - 1];
                }
            }
            long ans = 0L;
            for (int i = 1; i <= N; i++) {
                for (int j = 1; j <= M; j++) {
                    int maxSize = Math.min(N - i + 1, M - j + 1);
                    int lo = 1, hi = maxSize, best = -1;
                    while (lo <= hi) {
                        int mid = (lo + hi) >>> 1;
                        int i2 = i + mid - 1;
                        int j2 = j + mid - 1;
                        long sum = pref[i2][j2] - pref[i - 1][j2] - pref[i2][j - 1] + pref[i - 1][j - 1];
                        if (sum >= 0) { best = mid; hi = mid - 1; }
                        else lo = mid + 1;
                    }
                    if (best != -1) ans += (maxSize - best + 1);
                }
            }
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }

    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException { return Long.parseLong(next()); }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while ((c = readByte()) != -1 && c <= ' ') ; // skip whitespace
            if (c == -1) return "";
            do { sb.append((char) c); } while ((c = readByte()) != -1 && c > ' ');
            return sb.toString();
        }
    }
}

